        printf(del_a % x == 0 ? "YES\n" : "NO\n");
        return 0;
    }
    printf((del_a % x == 0 && del_b % y == 0 && (del_a / x) % 2 == (del_b / y) % 2) ? "YES\n" : "NO\n");
    return 0;
}
